-- Zeigen der Eingabezeile\set ECHO all -- Welche Tabellen gibt es? Es sollte noch keine geben.\dt -- Erstellen der Tabelle Studierende (zunächst ohne den Schlüssel auszuzeichnen)CREATE TABLE studierende (	vorname VARCHAR(80), 	name VARCHAR(80), 	matnr INT);-- Eintragen der beiden BeispielwerteINSERT INTO studierende VALUES ('Susi', 'Sinnlos', 4711);INSERT INTO studierende VALUES ('Rudi', 'Ratlos', 0815);INSERT INTO studierende VALUES ('Walter', 'Wichtig', 0815);-- Wir zeigen die komplette Tabelle anSELECT * FROM studierende; -- Ja, die Tabelle gibt es \dt-- und die Tabelle hat die gewünschten Eigenschaften (Relationenschema)\d studierende -- Wir räumen wieder auf und löschen die RelationDROP TABLE studierende; -- Das gibt ein Fehler, die Relation existiert nicht mehrSELECT * FROM studierende; -- Es gibt wieder keine Tabelle mehr in der Datenbank\dt